const body = $input.first().json.body || $input.first().json;
const payload = body.payload || body;

const { encounterNotes, encounterType, providerName } = payload;

if (!encounterNotes) {
  return [{ json: { success: false, error: 'Missing encounterNotes' } }];
}

// Structure the clinical note (LLM summarization would be called via the Dr. Claw llm-router)
const structuredNote = {
  encounterType: encounterType || 'office_visit',
  provider: providerName || 'Unknown Provider',
  rawNotes: encounterNotes,
  sections: {
    chiefComplaint: 'Extracted from notes by LLM',
    historyOfPresentIllness: 'Extracted from notes by LLM',
    assessment: 'Extracted from notes by LLM',
    plan: 'Extracted from notes by LLM'
  },
  suggestedCodes: [],
  status: 'draft',
  createdAt: new Date().toISOString(),
  source: 'n8n-clinical-documentation'
};

return [{ json: { success: true, document: structuredNote } }];
